mapper.select:
SELECT D.RN , D.BOARD_NO , D.BOARD_TYPE , D.CODE_NM , D.BOARD_NM , D.PARENT_CD , D.MENU_NM , D.USE_YN , D.COMMENT_YN FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.BOARD_NO) AS RN , A.BOARD_NO , A.BOARD_TYPE , B.CODE_NM , A.BOARD_NM , A.PARENT_CD , C.MENU_NM , A.USE_YN , A.COMMENT_YN FROM BOARD_MASTER A JOIN CODE_MASTER B ON A.BOARD_TYPE = CONCAT(B.CODE_LCD, B.CODE_SCD) JOIN ( SELECT MENU_LCD , MENU_NM FROM MENU_MASTER WHERE MENU_SCD = "00" ) C ON LEFT(A.PARENT_CD, 1) = C.MENU_LCD WHERE 1=1
AND A.BOARD_TYPE = #{schBoardType}
AND A.PARENT_CD = #{schParentCd}
AND A.USE_YN = #{schUseYn}
AND A.COMMENT_YN = #{schCommentYn}
AND A.BOARD_NM LIKE CONCAT('%', #{schBoardNm}, '%')
ORDER BY A.BOARD_NO ) D WHERE 1=1
AND D.RN BETWEEN (#{curIdx} + (#{pageUnit} * (#{curPage} - 1))) AND (#{pageUnit} + (#{pageUnit} * (#{curPage} - 1)))
ORDER BY D.RN , D.BOARD_NO

SELECT
	COUNT(*)
FROM
	BOARD_MASTER
WHERE
		1=1

	AND BOARD_TYPE = #{schBoardType}


	AND PARENT_CD = #{schParentCd}


	AND USE_YN = #{schUseYn}


	AND COMMENT_YN = #{schCommentYn}


	AND BOARD_NM LIKE CONCAT('%', #{schBoardNm}, '%')

mapper.insert:
INSERT INTO BOARD_MASTER
(
	BOARD_TYPE
  , BOARD_NM
  , PARENT_CD
  , USE_YN
  , COMMENT_YN
  , BOARD_NOTE
  , REG_NO
  , REG_DATE
  , UP_NO
  , UP_DATE
)
VALUES
(
	#{boardType}
  , #{boardNm}
  , #{parentCd}
  , #{useYn}
  , #{commentYn}
  , #{boardNote}
  , '1'
  , NOW()
  , '1'
  , NOW()
)

mapper.update:
UPDATE
	BOARD_MASTER
SET
	BOARD_TYPE = #{boardType}
  , BOARD_NM = #{boardNm}
  , PARENT_CD = #{parentCd}
  , USE_YN = #{useYn}
  , COMMENT_YN = #{commentYn}
  , BOARD_NOTE = #{boardNote}
  , UP_NO = '1'
  , UP_DATE = NOW()
WHERE
		1=1

	AND BOARD_NO = #{boardNo}
